// ─────────────────────────────────────────────────────────────────────────────
// EMAIL RANKING ENGINE
// Scores each email 1–5 and assigns a category label.
// Modify the keyword lists and scoring rules to fit your needs.
// ─────────────────────────────────────────────────────────────────────────────

const item = $input.item.json;

// ── Extract fields ───────────────────────────────────────────────────────────
const subject  = (item.subject  || '').toLowerCase();
const from     = (item.from     || '').toLowerCase();
const snippet  = (item.snippet  || '').toLowerCase();
const labelIds = item.labelIds  || [];
const body     = (item.text     || item.html || '').toLowerCase();

const fullText = `${subject} ${snippet} ${body}`;

// ── Scoring helpers ──────────────────────────────────────────────────────────
let score  = 3;          // default mid-point
let tags   = [];
let reason = [];

// ── SPAM / Junk detection (score 1) ──────────────────────────────────────────
const spamKeywords = [
  'unsubscribe', 'click here to unsubscribe', 'opt-out', 'opt out',
  'free offer', 'limited time offer', 'act now', 'winner',
  'you have been selected', 'congratulations', 'claim your prize',
  'earn money', 'make money fast', 'work from home',
  'nigerian prince', 'wire transfer', 'bitcoin', 'crypto bonus',
  'guaranteed income', 'no risk', '100% free',
  'cialis', 'viagra', 'pharmacy',
  'dear friend', 'dear beneficiary'
];

const spamDomains = [
  'noreply@', 'donotreply@', 'no-reply@',
  'marketing@', 'promo@', 'offers@', 'deals@',
  'newsletter@', 'news@', 'updates@'
];

const isGmailSpam = labelIds.includes('SPAM');
const hasSpamKeyword = spamKeywords.some(kw => fullText.includes(kw));
const hasSpamSender  = spamDomains.some(d => from.includes(d));

if (isGmailSpam || (hasSpamKeyword && hasSpamSender)) {
  score = 1;
  tags.push('RANK-1-SPAM');
  reason.push('Identified as spam');
}

// ── HIGH PRIORITY detection (score 5) ────────────────────────────────────────
const urgentKeywords = [
  'urgent', 'action required', 'immediate', 'asap',
  'deadline', 'time sensitive', 'critical', 'important',
  'invoice', 'payment due', 'overdue', 'past due'
];

const vipSenders = [
  // Add VIP email addresses or domains here
  // e.g., 'boss@company.com', '@mycompany.com'
];

const isUrgent = urgentKeywords.some(kw => subject.includes(kw) || snippet.includes(kw));
const isVip    = vipSenders.some(s => from.includes(s));
const isStar   = labelIds.includes('STARRED');
const isImportant = labelIds.includes('IMPORTANT');

if (score !== 1 && (isUrgent || isVip || isStar || isImportant)) {
  score = 5;
  tags.push('RANK-5-HIGH-PRIORITY');
  if (isUrgent)    reason.push('Urgent keywords detected');
  if (isVip)       reason.push('VIP sender');
  if (isStar)      reason.push('Starred by user');
  if (isImportant) reason.push('Marked important by Gmail');
}

// ── WORK / PROFESSIONAL (score 4) ────────────────────────────────────────────
const workKeywords = [
  'meeting', 'calendar invite', 'interview', 'proposal',
  'contract', 'project', 'report', 'review', 'feedback',
  'pull request', 'deployment', 'release', 'bug', 'issue',
  'github', 'jira', 'confluence', 'slack', 'figma'
];

const isWork = workKeywords.some(kw => fullText.includes(kw));

if (score === 3 && isWork) {
  score = 4;
  tags.push('RANK-4-WORK');
  reason.push('Work/professional content detected');
}

// ── NEWSLETTERS / SUBSCRIPTIONS (score 2) ────────────────────────────────────
const newsletterKeywords = [
  'unsubscribe', 'weekly digest', 'monthly newsletter',
  'roundup', 'edition', 'issue #', 'vol.', 'update from',
  'this week in', 'your daily', 'morning briefing'
];

const isNewsletter = newsletterKeywords.some(kw => fullText.includes(kw)) || hasSpamSender;

if (score === 3 && isNewsletter) {
  score = 2;
  tags.push('RANK-2-NEWSLETTER');
  reason.push('Newsletter or subscription content');
}

// ── Default fallback ─────────────────────────────────────────────────────────
if (tags.length === 0) {
  tags.push('RANK-3-NORMAL');
  reason.push('Normal email, no special classification');
}

// ── Output ───────────────────────────────────────────────────────────────────
return {
  ...item,
  _rank:          score,
  _rankTag:       tags[0],
  _rankReason:    reason.join('; '),
  _isSpam:        score === 1,
  _labelToApply:  tags[0]
};

// Log deletion for audit trail
const item = $input.item.json;
return {
  action:    'DELETED',
  messageId: item.id,
  subject:   item.subject,
  from:      item.from,
  reason:    item._rankReason,
  timestamp: new Date().toISOString()
};

// ─────────────────────────────────────────────────────────────────────────────
// EXTENSIBILITY HOOK — Add your custom post-processing logic here.
// This node runs after every non-spam email has been ranked and labelled.
//
// Examples of what you might add:
//   - Forward rank-5 emails to Slack
//   - Save summaries to a Google Sheet
//   - Create tasks in Todoist / Notion for rank-4 emails
//   - Auto-reply to newsletters
//   - Send a daily digest to yourself
// ─────────────────────────────────────────────────────────────────────────────

const item = $input.item.json;

return {
  messageId:   item.id,
  subject:     item.subject,
  from:        item.from,
  rank:        item._rank,
  rankTag:     item._rankTag,
  rankReason:  item._rankReason,
  processedAt: new Date().toISOString()
};
